mapper.select:
SELECT sc.id, sc.seller_id, sc.seller_Name, sc.celebrity_name, sc.celebrity_id, sc.create_time, scb.account, scb.avatar_url, scb.username, scb.nick_name, scb.email, scb.description, scb.following_num, scb.followers_num, scb.posts_num, scb.like_avg_num, scb.comment_avg_num, scb.play_avg_num, scb.tag, scb.country, scb.platform_type, scb.keyword, scb.new_tag, scb.face_status, scb.del_flag, scb.kol_price_min, scb.kol_price_max, scb.dislike_tags, scb.like_tags, scb.remark, scb.create_by, scb.update_by, scb.update_time, scb.is_tag_confirm, scb.star, scb.gender, smp.send_email_count AS sendEmailCount from store_seller_collection sc LEFT JOIN store_celebrity scb on scb.id = sc.celebrity_id LEFT JOIN ( SELECT kol_email, COUNT( id ) AS send_email_count FROM store_message_push_detail where seller_id = #{sellerCollectionAndCelebrityModel.sellerId} GROUP BY kol_email ) smp ON smp.kol_email = scb.email where sc.seller_id = #{sellerCollectionAndCelebrityModel.sellerId} and scb.del_flag = 0
and scb.platform_type = #{sellerCollectionAndCelebrityModel.platformType}
and IF(smp.send_email_count is null ,0,smp.send_email_count)=#{sellerCollectionAndCelebrityModel.sendEmailCount}
and scb.gender = #{sellerCollectionAndCelebrityModel.gender}
and (scb.gender <= -1 or scb.gender is null)
and scb.star=#{sellerCollectionAndCelebrityModel.star}
and scb.nick_name like '%${sellerCollectionAndCelebrityModel.nickName}%'
and scb.username like '%${sellerCollectionAndCelebrityModel.username}%'
and scb.country = #{sellerCollectionAndCelebrityModel.country}
AND find_in_set('${item}',like_tags)
AND find_in_set('${item}',dislike_tags)
and followers_num >= #{sellerCollectionAndCelebrityModel.followersStartNum}
and followers_num <= #{sellerCollectionAndCelebrityModel.followersEndNum}
and posts_num >= #{sellerCollectionAndCelebrityModel.postsStartNum}
and posts_num <= #{sellerCollectionAndCelebrityModel.postsEndNum}
and play_avg_num >= #{sellerCollectionAndCelebrityModel.playAvgStartNum}
and play_avg_num <= #{sellerCollectionAndCelebrityModel.playAvgEndNum}
ORDER BY sc.create_time desc
